import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  define: {
    // This ensures process.env exists in the browser context
    'process.env': {
      API_KEY: JSON.stringify(process.env.API_KEY || '')
